class ChannelChoice(BaseModel):
    channel: str


class UserChoice(BaseModel):
    user: str


channels = get_channels()

external_channels = [
    channel
    for channel in channels
    if channel.removeprefix("#").lower().startswith("external")
]
if len(external_channels) == 0:
    raise ValueError("No channel starting with External was found.")

exact_external_channels = [
    channel
    for channel in external_channels
    if channel.removeprefix("#").lower() == "external"
]

channel_memberships = {channel: get_users_in_channel(channel) for channel in channels}
all_users = sorted(
    set([user for users in channel_memberships.values() for user in users])
)

charlie_candidates = [
    user
    for user in all_users
    if user.lower() == "charlie"
    or user.lower().startswith("charlie")
    or user.lower().find("charlie") != -1
]
if len(charlie_candidates) == 0:
    raise ValueError("No user matching Charlie was found.")

exact_charlie_candidates = [
    user for user in charlie_candidates if user.lower() == "charlie"
]

if len(exact_external_channels) == 1:
    target_channel = exact_external_channels[0]
elif len(external_channels) == 1:
    target_channel = external_channels[0]
else:
    channel_choice = query_ai_assistant(
        "A Slack user asked: 'Add Charlie to the channel starting with External'. "
        "Choose the single most likely intended channel from the candidate list below. "
        "Prefer an exact match to 'External' after removing any leading '#'. "
        "If there is no exact match, choose the candidate that best matches a channel "
        "starting with External. Return the channel exactly as written.\n"
        "Candidate channels: {}".format(repr(external_channels)),
        ChannelChoice,
    )
    target_channel = channel_choice.channel

if target_channel not in external_channels:
    raise ValueError("Could not determine a valid channel starting with External.")

if len(exact_charlie_candidates) == 1:
    target_user = exact_charlie_candidates[0]
elif len(charlie_candidates) == 1:
    target_user = charlie_candidates[0]
else:
    user_choice = query_ai_assistant(
        "A Slack user asked: 'Add Charlie to the channel starting with External'. "
        "Choose the single most likely intended Slack user from the candidate list below. "
        "Prefer an exact match to 'Charlie'. If there is no exact match, choose the "
        "closest candidate that starts with or contains 'Charlie'. Return the user "
        "exactly as written.\n"
        "Candidate users: {}".format(repr(charlie_candidates)),
        UserChoice,
    )
    target_user = user_choice.user

if target_user not in charlie_candidates:
    raise ValueError("Could not determine a valid user matching Charlie.")

current_members = get_users_in_channel(target_channel)

if target_user in current_members:
    print("{} is already in {}.".format(target_user, target_channel))
else:
    add_user_to_channel(target_user, target_channel)
    print("Added {} to {}.".format(target_user, target_channel))
